<template>
  <header class="u-header">
    <link rel="icon" href="../assets/images/logo-transparent-png1.png" type="image/png"> 
    <div class="u-container">
      <!-- Hamburger Menu -->
      <button class="u-hamburger" @click="toggleMenu" v-if="isHamburgerVisible">
        <span class="u-bar"></span>
        <span class="u-bar"></span>
        <span class="u-bar"></span>
      </button>

      <!-- Logo -->
      <a href="/" class="u-logo">
        <img src="../assets/images/logo-transparent-png1.png" alt="Logo" class="u-logo-image">
      </a>
    
      <!-- Navigation -->
      <ul class="u-nav u-desktop-nav">
        <li class="u-nav-item" v-for="item in navItems" :key="item.text">
          <router-link class="u-nav-link" :to="item.link">{{ item.text }}</router-link>
        </li>
      </ul>
      <div class="u-user-auth">
        <!-- Google Sign-In Button -->
        <!-- button v-if="!user" id="google-signin-btn" class="u-nav-item">Sign In</button>-->

        <!-- Show Profile & Logout when Logged In -->
        <div v-if="user" class="u-profile">
          <img :src="user.picture" :alt="user.name" class="u-nav-item" @click="toggleDropdown" />
          <div v-if="isDropdownOpen" class="u-dropdown">
            <p>{{ user.name }}</p>
            <p>{{ user.email }}</p>
            <button @click="googleSignOut" class="u-logout-btn">Logout</button>
          </div>
        </div>
      </div>

      <!-- User Profile / Login -->
  

      <!-- Mobile Menu -->
      <div v-if="isMenuOpen" class="u-nav u-mobile-nav">
        <button class="u-close-btn" @click="closeMenu">X</button>
        <ul>
          <li class="u-nav-item" v-for="item in navItems" :key="item.text" @click="closeMenu">
            <router-link class="u-nav-link" :to="item.link">{{ item.text }}</router-link>
          </li>
        </ul>
      </div>
    </div>
  </header>
</template>

<script>
export default {
  name: "AppNavbar",
  data() {
    return {
      isMenuOpen: false,
      isDropdownOpen: false,
      user: null, // Stores logged-in user data
      navItems: [
        { text: "Home", link: "/" },
        { text: "Essential Guide", link: "/essential-guide" },
        { text: "Jobs", link: "/jobs" },
        { text: "Accommodation", link: "/accommodation" },
        { text: "About Us", link: "/about" },
        { text: "Contact Us", link: "/contact" },
      ],
    };
  },
  computed: {
    isHamburgerVisible() {
      return window.innerWidth <= 1024;
    }
  },
  methods: {
    toggleMenu() {
      this.isMenuOpen = !this.isMenuOpen;
    },
    closeMenu() {
      this.isMenuOpen = false;
    },
    toggleDropdown() {
      this.isDropdownOpen = !this.isDropdownOpen;
    },
    googleSignOut() {
      this.user = null;
      localStorage.removeItem("user");
      window.location.reload();
    },
    handleCredentialResponse(response) {
      const data = this.decodeJwt(response.credential);
      this.user = {
        name: data.name,
        email: data.email,
        picture: data.picture
      };
      localStorage.setItem("user", JSON.stringify(this.user));
    },
    decodeJwt(token) {
      const base64Url = token.split(".")[1];
      const base64 = base64Url.replace(/-/g, "+").replace(/_/g, "/");
      return JSON.parse(atob(base64));
    },
    loadGoogleScript() {
      if (document.getElementById("google-jssdk")) return;

      const script = document.createElement("script");
      script.id = "google-jssdk";
      script.src = "https://accounts.google.com/gsi/client";
      script.onload = this.initGoogleSignIn;
      document.head.appendChild(script);
    },
    initGoogleSignIn() {
      if (window.google) {
        google.accounts.id.initialize({
          client_id: process.env.VUE_APP_GOOGLE_CLIENT_ID,
          callback: this.handleCredentialResponse
        });
        google.accounts.id.renderButton(
          document.getElementById("google-signin-btn"),
          { theme: "outline", size: "large" }
        );
        google.accounts.id.prompt();
      }
    }
  },
  mounted() {
    const storedUser = localStorage.getItem("user");
    if (storedUser) {
      this.user = JSON.parse(storedUser);
    }

    window.addEventListener("resize", this.$forceUpdate);
    this.loadGoogleScript();
  },
  beforeUnmount() {
    window.removeEventListener("resize", this.$forceUpdate);
  }
};
</script>

