<template>
  <section class="contact-section">
    <div class="contact-container">
      <!-- Success Message -->
      <div v-if="formSubmitted" class="success-message">
        <h3>Thank you!</h3>
        <p>We have received your enquiry and will get in touch within 24 hours.</p>
      </div>

      <!-- Contact Form -->
      <div v-else class="contact-form">
        <h3 class="form-title">Get In Touch</h3>
        <p class="form-description">We’d love to hear from you! Contact us for any Queries.</p>

        <form @submit.prevent="handleSubmit" id="contactForm" novalidate>
          <input type="hidden" name="access_key" :value="apiKey" />
          <input type="hidden" name="subject" value="New Submission from Web3Forms" />
          <input type="checkbox" name="botcheck" style="display:none;" />

          <!-- First Name & Last Name -->
          <div class="form-row">
            <div class="form-group">
              <label for="first_name">First Name</label>
              <input
                type="text"
                class="form-input"
                id="first_name"
                name="name"
                v-model="formData.name"
                required
              />
              <div class="invalid-feedback">Please provide your first name.</div>
            </div>

            <div class="form-group">
              <label for="last_name">Last Name</label>
              <input
                type="text"
                class="form-input"
                id="last_name"
                name="last_name"
                v-model="formData.lastName"
                required
              />
              <div class="invalid-feedback">Please provide your last name.</div>
            </div>
          </div>

          <!-- Email & Phone -->
          <div class="form-row">
            <div class="form-group">
              <label for="email">Email Address</label>
              <input
                type="email"
                class="form-input"
                id="email"
                name="email"
                v-model="formData.email"
                required
              />
              <div class="invalid-feedback">Please provide a valid email address.</div>
            </div>

            <div class="form-group">
              <label for="phone">Phone Number</label>
              <input
                type="tel"
                class="form-input"
                id="phone"
                name="phone"
                v-model="formData.phone"
                placeholder="Please use country code"
                required
              />
              <div class="invalid-feedback">Please provide your phone number.</div>
            </div>
          </div>

          <!-- Message -->
          <div class="form-group">
            <label for="message">Your Message</label>
            <textarea
              class="form-input"
              id="message"
              name="message"
              v-model="formData.message"
              rows="4"
              required
            ></textarea>
            <div class="invalid-feedback">Please enter your message.</div>
          </div>

          <!-- Submit Button -->
          <div class="form-submit">
            <button type="submit" class="submit-btn">Send Message</button>
          </div>
        </form>
      </div>
    </div>
  </section>
</template>

<script>
import axios from "axios";

export default {
  name: "AppContacts",
  data() {
    return {
      apiKey: process.env.VUE_APP_WEB3FORMS_API_KEY, // Replace with your Web3Forms API key if not using environment variables
      formSubmitted: false, // Tracks if the form was successfully submitted
      formData: {
        name: "",
        lastName: "",
        email: "",
        phone: "",
        message: "",
      },
    };
  },
  methods: {
    async handleSubmit() {
      try {
        const response = await axios.post("https://api.web3forms.com/submit", {
          access_key: this.apiKey,
          ...this.formData,
        });

        if (response.status === 200) {
          // Form submission success
          this.formSubmitted = true;
        }
      } catch (error) {
        console.error("Error submitting the form:", error);
        alert("Something went wrong. Please try again later.");
      }
    },
  },
};
</script>

