import { createRouter, createWebHistory } from 'vue-router';

// Import your components
import Home from '@/Pages/Home.vue'; 
import EssentialGuide from '@/Pages/EssentialGuide.vue'; 
import Jobs from '@/Pages/Jobs.vue'; 
import Accommodation from '@/Pages/Accommodation.vue'; 
import About from '@/Pages/About.vue'; 
import Contacts from '@/Pages/Contacts.vue';
import PropertyDetails from '@/Pages/PropertyDetails.vue';

const routes = [
  {
    path: '/',
    name: 'Home',
    component: Home,
    meta: {
      title: 'Home - Student Journey Mentor'
    }
  },
  {
    path: '/essential-guide',
    name: 'EssentialGuide',
    component: EssentialGuide,
    meta: {
      title: 'Essential Guide - Student Journey Mentor'
    }
  },
  {
    path: '/jobs',
    name: 'Jobs',
    component: Jobs,
    meta: {
      title: 'Jobs - Student Journey Mentor'
    }
  },
  {
    path: '/accommodation',
    name: 'Accommodation',
    component: Accommodation,
    meta: {
      title: 'Accommodation - Student Journey Mentor'
    }
  },
  {
    path: '/about',
    name: 'About',
    component: About,
    meta: {
      title: 'About Us - Student Journey Mentor'
    }
  },
  {
    path: '/contact',
    name: 'Contacts',
    component: Contacts,
    meta: {
      title: 'Contact Us - Student Journey Mentor'
    }
  },
  {
    path: '/property/:offerid',
    name: 'PropertyDetails',
    component: PropertyDetails,
    meta: {
      title: 'Property Details - Student Journey Mentor'
    }
  }
  
  
];

const router = createRouter({
  history: createWebHistory(),
  routes,
});

export default router;
